def PublishArticle(title: str, content: str, reviewer: str) -> dict:
    if not ValidateContent(title, content):
        return {"article_id": None, "published_at": None, "reviewer": reviewer, "status": "validation_failed", "word_count": len(content.split())}
    article_id = SchedulePublish(title, content)
    NotifyReviewer(reviewer, article_id)
    from datetime import datetime
    published_at = datetime.now().isoformat()
    word_count = len(content.split())
    return {"article_id": article_id, "published_at": published_at, "reviewer": reviewer, "status": "published", "word_count": word_count}
